from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


class CronParseError(ValueError):
    """Raised when a cron expression is malformed or outside valid ranges."""


@dataclass(frozen=True)
class CronField:
    name: str
    minimum: int
    maximum: int
    values: tuple[int, ...]
    source: str

    def is_wildcard(self) -> bool:
        return self.values == tuple(range(self.minimum, self.maximum + 1))

    def is_single_value(self) -> bool:
        return len(self.values) == 1

    def only_value(self) -> int:
        if not self.is_single_value():
            raise CronParseError(f"{self.name} does not contain exactly one value")
        return self.values[0]


@dataclass(frozen=True)
class CronSchedule:
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    @classmethod
    def parse(cls, expression: str) -> CronSchedule:
        parts = expression.split()
        if len(parts) != 5:
            raise CronParseError(
                f"Expected 5 cron fields, got {len(parts)}: {expression!r}"
            )

        return cls(
            minute=parse_field(parts[0], "minute", 0, 59),
            hour=parse_field(parts[1], "hour", 0, 23),
            day_of_month=parse_field(parts[2], "day_of_month", 1, 31),
            month=parse_field(parts[3], "month", 1, 12),
            day_of_week=parse_field(parts[4], "day_of_week", 0, 6),
        )

    def describe(self) -> str:
        return describe_schedule(self)


def parse_cron(expression: str) -> CronSchedule:
    return CronSchedule.parse(expression)


def parse_field(source: str, name: str, minimum: int, maximum: int) -> CronField:
    if not source:
        raise CronParseError(f"{name} field cannot be empty")

    values: set[int] = set()

    for list_part in source.split(","):
        if not list_part:
            raise CronParseError(f"{name} field contains an empty list item: {source!r}")

        values.update(parse_field_part(list_part, name, minimum, maximum))

    if not values:
        raise CronParseError(f"{name} field did not produce any values: {source!r}")

    return CronField(
        name=name,
        minimum=minimum,
        maximum=maximum,
        values=tuple(sorted(values)),
        source=source,
    )


def parse_field_part(part: str, name: str, minimum: int, maximum: int) -> set[int]:
    base, step = split_step(part, name)
    base_values = parse_base_values(base, name, minimum, maximum)

    if step is None:
        return base_values

    return {
        value
        for index, value in enumerate(sorted(base_values))
        if index % step == 0
    }


def split_step(part: str, name: str) -> tuple[str, int | None]:
    if "/" not in part:
        return part, None

    pieces = part.split("/")
    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"Invalid step syntax in {name} field: {part!r}")

    step = parse_int(pieces[1], name)

    if step <= 0:
        raise CronParseError(f"Step must be greater than zero in {name} field: {part!r}")

    return pieces[0], step


def parse_base_values(base: str, name: str, minimum: int, maximum: int) -> set[int]:
    if base == "*":
        return set(range(minimum, maximum + 1))

    if "-" in base:
        return parse_range(base, name, minimum, maximum)

    value = parse_int(base, name)
    validate_range(value, name, minimum, maximum)
    return {value}


def parse_range(source: str, name: str, minimum: int, maximum: int) -> set[int]:
    pieces = source.split("-")

    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"Invalid range syntax in {name} field: {source!r}")

    start = parse_int(pieces[0], name)
    end = parse_int(pieces[1], name)

    validate_range(start, name, minimum, maximum)
    validate_range(end, name, minimum, maximum)

    if start > end:
        raise CronParseError(
            f"Range start must be <= range end in {name} field: {source!r}"
        )

    return set(range(start, end + 1))


def parse_int(source: str, name: str) -> int:
    if not source.isdigit():
        raise CronParseError(f"Expected an integer in {name} field, got {source!r}")

    return int(source)


def validate_range(value: int, name: str, minimum: int, maximum: int) -> None:
    if value < minimum or value > maximum:
        raise CronParseError(
            f"{name} value {value} is outside allowed range {minimum}-{maximum}"
        )


