def describe_values(field: CronField) -> str:
    if field.is_wildcard():
        return "every value"

    if field.is_single_value():
        return str(field.only_value())

    return join_english([str(value) for value in field.values])


def is_contiguous(values: list[int]) -> bool:
    return values == list(range(values[0], values[-1] + 1))


def join_english(items: list[str]) -> str:
    if not items:
        return ""

    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


